    int userId;
    Tweet tweets[MAX_TWEETS];
    int tweetCount;
    int followers[MAX_USERS];
    int followerCount;
} User;

User users[MAX_USERS];

void postTweet(int userId, int tweetId) {
    users[userId].tweets[users[userId].tweetCount].userId = userId;
    users[userId].tweets[users[userId].tweetCount].tweetId = tweetId;
    users[userId].tweets[users[userId].tweetCount].timestamp = users[userId].tweetCount;
    users[userId].tweetCount++;
}

void follow(int followerId, int followeeId) {
    users[followerId].followers[users[followerId].followerCount] = followeeId;
    users[followerId].followerCount++;
}

void unfollow(int followerId, int followeeId) {
    for (int i = 0; i < users[followerId].followerCount; i++) {
        if (users[followerId].followers[i] == followeeId) {
            users[followerId].followers[i] = users[followerId].followers[users[followerId].followerCount - 1];
            users[followerId].followerCount--;
            break;
        }
    }
}

int* getNewsFeed(int userId, int* returnSize) {
    int* newsFeed = (int*)malloc(10 * sizeof(int));
    *returnSize = 0;
    for (int i = users[userId].tweetCount - 1; i >= 0; i--) {
        newsFeed[*returnSize] = users[userId].tweets[i].tweetId;
        (*returnSize)++;
        if (*returnSize == 10) break;
    }
    for (int i = 0; i < users[userId].followerCount; i++) {
        int followeeId = users[userId].followers[i];
        for (int j = users[followeeId].tweetCount - 1; j >= 0; j--) {
            newsFeed[*returnSize] = users[followeeId].tweets[j].tweetId;
            (*returnSize)++;
            if (*returnSize == 10) break;
        }
        if (*returnSize == 10) break;
    }
    return newsFeed;
}

