class Twitter {
    private int timestamp;
    private Map<Integer, List<Tweet>> tweets;
    private Map<Integer, Set<Integer>> following;

    public Twitter() {
        timestamp = 0;
        tweets = new HashMap<>();
        following = new HashMap<>();
    }

    public void postTweet(int userId, int tweetId) {
        tweets.putIfAbsent(userId, new ArrayList<>());
        tweets.get(userId).add(new Tweet(tweetId, timestamp++));
    }

    public List<Integer> getNewsFeed(int userId) {
        List<Integer> newsFeed = new ArrayList<>();
        for (Tweet tweet : tweets.getOrDefault(userId, new ArrayList<>())) {
            newsFeed.add(tweet.tweetId);
        }
        for (int followee : following.getOrDefault(userId, new HashSet<>())) {
            for (Tweet tweet : tweets.getOrDefault(followee, new ArrayList<>())) {
                newsFeed.add(tweet.tweetId);
            }
        }
        Collections.sort(newsFeed, (a, b) -> b - a);
        if (newsFeed.size() > 10) newsFeed.subList(10, newsFeed.size()).clear();
        return newsFeed;
    }

    public void follow(int followerId, int followeeId) {
        following.putIfAbsent(followerId, new HashSet<>());
        following.get(followerId).add(followeeId);
    }

    public void unfollow(int followerId, int followeeId) {
        following.getOrDefault(followerId, new HashSet<>()).remove(followeeId);
    }
}

